const fs = require('fs');

const LVW_HEADER_HEX = "";
const LVW_FOOTER_HEX = "";

function fromHex(hex) {
    return Buffer.from(hex, 'hex');
}

const header = fromHex(LVW_HEADER_HEX);
const footer = fromHex(LVW_FOOTER_HEX);

// Simple component simulated (AND gate)
const comp = Buffer.concat([
    Buffer.from([0x22, 0x12, 0x00, 0x02]), 
    Buffer.from([0xd0, 0x07, 0x00, 0x00]), // Xpos (2000)
    Buffer.from([0xd0, 0x07, 0x00, 0x00]), // Ypos (2000)
    Buffer.from([0x00]), // label length 0
    Buffer.from([0x00, 0x00, 0x05, 0x00, 0x00, 0x00])
]);

const buffer = Buffer.concat([header, comp, footer]);
fs.writeFileSync('gen.lvw', buffer);
